SELECT COUNT(*)
FROM document_authors
WHERE author_id = 1;

SELECT COUNT(*) 
FROM workspace_members 
WHERE workspace_id = (SELECT workspace_id FROM shared_workspaces WHERE workspace_name = 'Policy Development');

SELECT COUNT(doc_id) AS document_count
FROM workspace_documents
WHERE workspace_id = 1;

SELECT COUNT(doc_id) AS document_count
FROM document_topics
WHERE topic_id = 1;

SELECT doc_id, topic_id
FROM document_topics
WHERE relevance_score >= 80;
